import React from 'react';
import { Bar, Line } from 'react-chartjs-2';

interface StatisticsProps {
  totalSales: number;
  activeUsers: number;
  inventoryLevels: number;
  salesData: { labels: string[]; datasets: any[] };
  userGrowthData: { labels: string[]; datasets: any[] };
}

const Statistics: React.FC<StatisticsProps> = ({ totalSales, activeUsers, inventoryLevels, salesData, userGrowthData }) => {
  return (
    <section className="py-8 bg-gray-900">
      <div className="max-w-6xl mx-auto px-4">
        <h2 className="text-2xl font-semibold text-white mb-6">Dashboard Overview</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-gray-800 p-6 rounded-xl shadow-md">
            <h3 className="text-lg text-white">Total Sales</h3>
            <p className="text-3xl font-bold text-indigo-400">${totalSales}</p>
          </div>
          <div className="bg-gray-800 p-6 rounded-xl shadow-md">
            <h3 className="text-lg text-white">Active Users</h3>
            <p className="text-3xl font-bold text-indigo-400">{activeUsers}</p>
          </div>
          <div className="bg-gray-800 p-6 rounded-xl shadow-md">
            <h3 className="text-lg text-white">Inventory Levels</h3>
            <p className="text-3xl font-bold text-indigo-400">{inventoryLevels}</p>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-gray-800 p-6 rounded-xl shadow-md">
            <h3 className="text-lg text-white mb-4">Sales Data</h3>
            <Line data={salesData} options={{ maintainAspectRatio: false }} />
          </div>
          <div className="bg-gray-800 p-6 rounded-xl shadow-md">
            <h3 className="text-lg text-white mb-4">User Growth</h3>
            <Bar data={userGrowthData} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      </div>
    </section>
  );
};

export default Statistics;
